import time
import threading

# --- POLLING APPROACH ---
class PollingAgent:
    def __init__(self, poll_interval_s=5):
        self.poll_interval_s = poll_interval_s
        self._running = False

    def check_environment(self):
        # Simulated: returns None when nothing changed
        return None

    def react(self, change):
        print('[PollingAgent] Reacting to: ' + str(change))

    def run(self, max_cycles=3):
        for _ in range(max_cycles):
            change = self.check_environment()
            if change is not None:
                self.react(change)
            time.sleep(self.poll_interval_s)


# --- PUSH APPROACH ---
class PushAgent:
    def on_change(self, change):
        # Called immediately when the environment changes
        print('[PushAgent] Reacting to: ' + str(change))

def simulate_push_notification(agent):
    # In a real system this is a webhook, SIGTERM, asyncio callback, etc.
    event = {'type': 'file_modified', 'path': '/etc/config.yaml'}
    agent.on_change(event)

push_agent = PushAgent()
simulate_push_notification(push_agent)

