# Minimal ReAct loop showing the reactive observation step
from dataclasses import dataclass, field

@dataclass
class Step:
    thought: str
    action: str
    action_input: str
    observation: str = ''

class ReActAgent:
    def __init__(self, tools):
        self.tools = tools  # dict: tool_name -> callable
        self.history = []

    def run(self, goal, max_steps=5):
        print('Goal: ' + goal)
        for step_num in range(max_steps):
            # 1. Deliberate: decide what to do (LLM call in production)
            thought, action, action_input = self._think(goal, self.history)

            if action == 'finish':
                print('Done: ' + action_input)
                return action_input

            # 2. Act: call the tool
            if action not in self.tools:
                observation = 'ERROR: unknown tool ' + action
            else:
                observation = self.tools[action](action_input)

            # 3. React: record the observation and loop
            step = Step(thought, action, action_input, observation)
            self.history.append(step)
            print('Step ' + str(step_num+1) + ': ' + action + '(' + action_input + ') -> ' + observation)

        return 'max steps reached'

    def _think(self, goal, history):
        # Stub: real impl calls an LLM with goal + history
        if not history:
            return 'I need to look up the answer', 'search', goal
        last = history[-1]
        if 'ERROR' in last.observation:
            return 'Previous step failed. I will finish with partial info.', 'finish', 'Unable to complete'
        return 'I have an answer', 'finish', last.observation

agent = ReActAgent(tools={
    'search': lambda q: 'The capital of France is Paris.',
})
agent.run('What is the capital of France?')

class ThresholdReactor:
    def __init__(self, metric_name, threshold, action):
        self.metric_name = metric_name
        self.threshold = threshold
        self.action = action
        self._was_above = False

    def observe(self, value):
        is_above = value > self.threshold
        if is_above and not self._was_above:
            # Rising edge: just crossed the threshold
            self.action(self.metric_name, value)
        self._was_above = is_above

def alert(name, value):
    print('ALERT: ' + name + ' = ' + str(value) + ' exceeds threshold')

reactor = ThresholdReactor('cpu_pct', threshold=80, action=alert)
for reading in [60, 75, 85, 90, 78, 82]:
    reactor.observe(reading)
# ALERT fires at 85 (first crossing), not at 90 or 82 (still above or re-crossing)

class StateChangeDetector:
    def __init__(self):
        self._last_state = {}
        self._handlers = {}

    def on_transition(self, from_state, to_state, handler):
        key = (from_state, to_state)
        self._handlers[key] = handler

    def observe(self, entity_id, new_state):
        old_state = self._last_state.get(entity_id)
        self._last_state[entity_id] = new_state
        if old_state != new_state:
            handler = self._handlers.get((old_state, new_state))
            if handler:
                handler(entity_id, old_state, new_state)

def on_pr_merged(entity_id, from_s, to_s):
    print('PR ' + entity_id + ' merged -- triggering deploy pipeline')

def on_pr_closed(entity_id, from_s, to_s):
    print('PR ' + entity_id + ' closed without merge -- cleaning up branch')

detector = StateChangeDetector()
detector.on_transition('open', 'merged', on_pr_merged)
detector.on_transition('open', 'closed', on_pr_closed)

detector.observe('PR-42', 'open')
detector.observe('PR-42', 'merged')
detector.observe('PR-99', 'open')
detector.observe('PR-99', 'closed')

from dataclasses import dataclass, field
from typing import Callable

@dataclass
class Outcome:
    success: bool
    value: object = None
    error: str = ''

class FaultTolerantReactiveAgent:
    def __init__(self):
        self.retry_handlers = {}
        self.fallback_handlers = {}

    def on_retry(self, error_type):
        def decorator(fn):
            self.retry_handlers[error_type] = fn
            return fn
        return decorator

    def on_fallback(self, error_type):
        def decorator(fn):
            self.fallback_handlers[error_type] = fn
            return fn
        return decorator

    def call_tool(self, tool_fn, *args, max_retries=2):
        for attempt in range(max_retries + 1):
            try:
                result = tool_fn(*args)
                return Outcome(success=True, value=result)
            except TimeoutError as exc:
                handler = self.retry_handlers.get('timeout')
                if handler and attempt < max_retries:
                    handler(attempt, str(exc))
                    continue
                fallback = self.fallback_handlers.get('timeout')
                if fallback:
                    return Outcome(success=False, value=fallback(str(exc)))
                return Outcome(success=False, error=str(exc))
            except Exception as exc:
                return Outcome(success=False, error=str(exc))
        return Outcome(success=False, error='max retries exceeded')

agent = FaultTolerantReactiveAgent()

@agent.on_retry('timeout')
def log_retry(attempt, msg):
    print('Retry attempt ' + str(attempt+1) + ' after timeout: ' + msg)

@agent.on_fallback('timeout')
def serve_cached(msg):
    print('Serving cached result due to: ' + msg)
    return 'cached_value'

# Simulate a tool that always times out
def flaky_tool(query):
    raise TimeoutError('connection timed out after 30s')

result = agent.call_tool(flaky_tool, 'some query')
print('Final outcome:', result)
